// Chunk configuration (manual config here)
const chunkSize = 1100;
const overlap = 180;

const items = $input.all();
const output = [];

for (const item of items) {
  const text = (item.json.content || item.json.text || '').trim();
  const url = item.json.url || '';
  const title = item.json.title || '';

  let start = 0;
  let idx = 0;

  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    const piece = text.slice(start, end).trim();

    if (piece.length >= 80) {
      output.push({
        json: {
          content: piece,
          url,
          title,
          chunk_index: idx++
        }
      });
    }

    if (end >= text.length) break;

    start = end - overlap;
    if (start < 0) start = 0;
  }
}

return output;

// Get data from previous node
const inputData = $input.all();

// Default empty array
let urls = [];

// Extract URLs safely (correct nested path)
if (
  inputData.length > 0 &&
  inputData[0].json?.data?.data?.urls &&
  Array.isArray(inputData[0].json.data.data.urls)
) {
  urls = inputData[0].json.data.data.urls;
}

// Return each URL as separate item
return urls.map((url, index) => ({
  json: {
    url,
    index: index + 1
  }
}));

// Get current item
const item = $input.item;

// Safely extract content
const content = item.json?.data?.data?.content || "";
const url = item.json?.data?.url || "";
const title = item.json?.data?.data?.content || "";

// Return only content
return {
  json: {
    url,
    title,
    content
  }
};
